fn solve(s: String) -> i64 {
    let n = s.len();
    let s_bytes = s.as_bytes();
    let mut prefixL = vec![0i64; n + 1];
    for i in 0..n {
        prefixL[i + 1] = prefixL[i] + if s_bytes[i] == b'L' { 1 } else { 0 };
    }

    let mut suffixT0 = vec![0i64; n + 1];
    for i in (0..n).rev() {
        suffixT0[i] = suffixT0[i + 1] + if s_bytes[i] == b'T' { 1 } else { 0 };
    }

    let mut base_count = 0i64;
    for i in 0..n {
        if s_bytes[i] == b'C' {
            base_count += prefixL[i] * suffixT0[i + 1];
        }
    }

    let mut G = vec![0i64; n + 1];
    for i in (0..n).rev() {
        G[i] = G[i + 1];
        if s_bytes[i] == b'C' {
            G[i] += suffixT0[i + 1];
        }
    }

    let mut H = vec![0i64; n + 1];
    let mut countL = 0i64;
    for i in 0..n {
        if s_bytes[i] == b'L' {
            countL += 1;
            H[i + 1] = H[i];
        } else if s_bytes[i] == b'C' {
            H[i + 1] = H[i] + countL;
        } else {
            H[i + 1] = H[i];
        }
    }

    let cand1 = *G.iter().max().unwrap_or(&0);
    let cand2 = (0..=n).map(|i| prefixL[i] * suffixT0[i]).max().unwrap_or(0);
    let cand3 = *H.iter().max().unwrap_or(&0);

    let ans = base_count
        .max(base_count + cand1)
        .max(base_count + cand2)
        .max(base_count + cand3);

    ans
}
